import{_ as a,c as o,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Google Cloud: Consulta de cuota | opencode-mystatus","description":"Aprende a consultar la cuota de Google Cloud para G3 Pro, G3 Image, G3 Flash y Claude. Ver cuotas restantes y tiempos de restablecimiento.","frontmatter":{"title":"Google Cloud: Consulta de cuota | opencode-mystatus","sidebarTitle":"Cuota Google","subtitle":"Google Cloud: Consulta de cuota","description":"Aprende a consultar la cuota de Google Cloud para G3 Pro, G3 Image, G3 Flash y Claude. Ver cuotas restantes y tiempos de restablecimiento.","tags":["Google Cloud","Antigravity","consulta de cuota"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"es/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"es/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),l={name:"es/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function n(i,e,r,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="consulta-de-cuota-de-google-cloud-g3-pro-image-flash-y-claude" tabindex="-1">Consulta de cuota de Google Cloud: G3 Pro/Image/Flash y Claude <a class="header-anchor" href="#consulta-de-cuota-de-google-cloud-g3-pro-image-flash-y-claude" aria-label="Permalink to &quot;Consulta de cuota de Google Cloud: G3 Pro/Image/Flash y Claude&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>Ver la cuota de los 4 modelos de la cuenta de Google Cloud Antigravity</li><li>Comprender el tiempo de restablecimiento y el porcentaje restante de cada modelo</li><li>Gestionar el uso de cuotas de múltiples cuentas de Google Cloud</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Google Cloud Antigravity proporciona múltiples modelos (G3 Pro、G3 Image、G3 Flash、Claude), cada modelo tiene una cuota independiente y tiempo de restablecimiento. Necesitas:</p><ul><li>Iniciar sesión individualmente en la consola de Google Cloud para ver el estado de cada modelo</li><li>Calcular manualmente la cuota restante y el tiempo de restablecimiento</li><li>Gestionar múltiples cuentas, lo cual es aún más confuso</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando tú:</p><ul><li>Quieres conocer rápidamente todas las cuotas restantes de los modelos de Google Cloud</li><li>Necesitas planificar la distribución de uso entre diferentes modelos</li><li>Tienes múltiples cuentas de Google Cloud que necesitan gestión unificada</li></ul><h2 id="🎒-preparativos" tabindex="-1">🎒 Preparativos <a class="header-anchor" href="#🎒-preparativos" aria-label="Permalink to &quot;🎒 Preparativos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Verificación previa</p><ol><li><strong>Instalado el plugin mystatus</strong>: Consulta <a href="/docs/opencodedocs/es/vbgate/opencode-mystatus/start/quick-start/">Inicio rápido</a></li><li><strong>Configurada la autenticación de Google Cloud</strong>: Necesitas instalar primero el plugin <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> para completar la autenticación OAuth</li><li><strong>Archivo de autenticación existe</strong>: <code>~/.config/opencode/antigravity-accounts.json</code> contiene al menos una cuenta</li></ol></div><h2 id="enfoque-central" tabindex="-1">Enfoque central <a class="header-anchor" href="#enfoque-central" aria-label="Permalink to &quot;Enfoque central&quot;">​</a></h2><p>Google Cloud Antigravity se autentica mediante el mecanismo OAuth, cada cuenta tiene un Refresh Token independiente. El plugin mystatus:</p><ol><li>Lee <code>antigravity-accounts.json</code> para obtener todas las cuentas configuradas</li><li>Usa Refresh Token para refrescar Access Token</li><li>Llama a la API de Google Cloud para obtener la cuota de todos los modelos</li><li>Muestra la cuota y tiempo de restablecimiento de los 4 modelos agrupados por cuenta</li></ol><h2 id="modelos-soportados-por-google-cloud" tabindex="-1">Modelos soportados por Google Cloud <a class="header-anchor" href="#modelos-soportados-por-google-cloud" aria-label="Permalink to &quot;Modelos soportados por Google Cloud&quot;">​</a></h2><p>mystatus muestra la cuota de los siguientes 4 modelos:</p><table tabindex="0"><thead><tr><th>Nombre de visualización</th><th>Modelo Key (principal/respaldo)</th><th>Descripción</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro versión de alto rendimiento</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro generación de imágenes</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash versión rápida</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Modelo Claude Opus 4.5</td></tr></tbody></table><p><strong>Mecanismo de key principal y de respaldo</strong>:</p><ul><li>La respuesta de la API puede devolver datos solo del key principal o del key de respaldo</li><li>mystatus intentará automáticamente obtener la cuota de cualquier key</li><li>Por ejemplo: si <code>gemini-3-pro-high</code> no tiene datos, intentará con <code>gemini-3-pro-low</code></li></ul><h2 id="sigue-los-pasos" tabindex="-1">Sigue los pasos <a class="header-anchor" href="#sigue-los-pasos" aria-label="Permalink to &quot;Sigue los pasos&quot;">​</a></h2><h3 id="paso-1-ejecuta-el-comando-de-consulta" tabindex="-1">Paso 1: Ejecuta el comando de consulta <a class="header-anchor" href="#paso-1-ejecuta-el-comando-de-consulta" aria-label="Permalink to &quot;Paso 1: Ejecuta el comando de consulta&quot;">​</a></h3><p><strong>Por qué</strong> Obtener rápidamente información de cuota de todas las cuentas de Google Cloud</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>Lo que deberías ver</strong> Incluye información de cuota de todas las plataformas configuradas, donde la sección de Google Cloud mostrará contenido similar a:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="paso-2-comprende-el-formato-de-salida" tabindex="-1">Paso 2: Comprende el formato de salida <a class="header-anchor" href="#paso-2-comprende-el-formato-de-salida" aria-label="Permalink to &quot;Paso 2: Comprende el formato de salida&quot;">​</a></h3><p><strong>Por qué</strong> Localizar rápidamente información clave: cuota restante y tiempo de restablecimiento</p><p>Formato de cada línea:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Nombre del modelo] [Tiempo de restablecimiento] [Barra de progreso] [Porcentaje restante]</span></span></code></pre></div><p><strong>Explicación de campos</strong>:</p><ul><li><strong>Nombre del modelo</strong>: G3 Pro, G3 Image, G3 Flash, Claude</li><li><strong>Tiempo de restablecimiento</strong>: Tiempo restante hasta la siguiente renovación de cuota (como <code>4h 59m</code>、<code>2d 9h</code>)</li><li><strong>Barra de progreso</strong>: Visualiza intuitivamente el porcentaje restante</li><li><strong>Porcentaje restante</strong>: Valor de 0-100</li></ul><p><strong>Lo que deberías ver</strong> Cada modelo en una línea, mostrando claramente la cuota y el tiempo de restablecimiento</p><h3 id="paso-3-revisa-la-situacion-de-multiples-cuentas" tabindex="-1">Paso 3: Revisa la situación de múltiples cuentas <a class="header-anchor" href="#paso-3-revisa-la-situacion-de-multiples-cuentas" aria-label="Permalink to &quot;Paso 3: Revisa la situación de múltiples cuentas&quot;">​</a></h3><p><strong>Por qué</strong> Si tienes múltiples cuentas de Google Cloud, se mostrarán por separado</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ██████████░░░░░░░░░ 50%</span></span></code></pre></div><p><strong>Lo que deberías ver</strong> Cada cuenta en un bloque separado, conteniendo las cuotas de los 4 modelos de esa cuenta</p><h3 id="paso-4-verifica-advertencias-de-cuota" tabindex="-1">Paso 4: Verifica advertencias de cuota <a class="header-anchor" href="#paso-4-verifica-advertencias-de-cuota" aria-label="Permalink to &quot;Paso 4: Verifica advertencias de cuota&quot;">​</a></h3><p><strong>Por qué</strong> Evitar que el uso excesivo cause interrupciones del servicio</p><p>Si la tasa de uso de cualquier modelo supera el 80%, se mostrará una advertencia:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 使用率已达到或超过 80%</span></span></code></pre></div><p><strong>Lo que deberías ver</strong> La advertencia aparece debajo de la lista de modelos de la cuenta correspondiente</p><h2 id="punto-de-control-✅" tabindex="-1">Punto de control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de control ✅&quot;">​</a></h2><p>Completa las siguientes verificaciones para asegurar que lo hiciste correctamente:</p><ul><li>[ ] Después de ejecutar <code>/mystatus</code> puedes ver la información de cuota de Google Cloud</li><li>[ ] Comprendes los nombres y tiempos de restablecimiento de los 4 modelos</li><li>[ ] Puedes identificar la barra de progreso y el porcentaje restante</li><li>[ ] Si hay múltiples cuentas, puedes ver la cuota de todas las cuentas</li></ul><h2 id="advertencias-de-errores-comunes" tabindex="-1">Advertencias de errores comunes <a class="header-anchor" href="#advertencias-de-errores-comunes" aria-label="Permalink to &quot;Advertencias de errores comunes&quot;">​</a></h2><h3 id="problema-1-no-se-ve-la-cuota-de-google-cloud" tabindex="-1">Problema 1: No se ve la cuota de Google Cloud <a class="header-anchor" href="#problema-1-no-se-ve-la-cuota-de-google-cloud" aria-label="Permalink to &quot;Problema 1: No se ve la cuota de Google Cloud&quot;">​</a></h3><p><strong>Posibles causas</strong>:</p><ul><li>No se ha instalado el plugin opencode-antigravity-auth</li><li>No se ha completado la autenticación OAuth de Google</li><li>El archivo <code>antigravity-accounts.json</code> no existe o está vacío</li></ul><p><strong>Solución</strong>:</p><ol><li>Instala el plugin opencode-antigravity-auth</li><li>Completa la autenticación según las instrucciones del repositorio de GitHub</li><li>Ejecuta <code>/mystatus</code> nuevamente</li></ol><h3 id="problema-2-una-cuenta-muestra-error" tabindex="-1">Problema 2: Una cuenta muestra error <a class="header-anchor" href="#problema-2-una-cuenta-muestra-error" aria-label="Permalink to &quot;Problema 2: Una cuenta muestra error&quot;">​</a></h3><p><strong>Posibles causas</strong>:</p><ul><li>El Refresh Token ha expirado</li><li>Falta el projectId</li></ul><p><strong>Ejemplo de error</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>Solución</strong>:</p><ol><li>Autentica nuevamente la cuenta usando el plugin opencode-antigravity-auth</li><li>Asegúrate de configurar correctamente el ID del proyecto durante el proceso de autenticación</li></ol><h3 id="problema-3-el-modelo-muestra-o-tiempo-de-restablecimiento-anormal" tabindex="-1">Problema 3: El modelo muestra &quot;-&quot; o tiempo de restablecimiento anormal <a class="header-anchor" href="#problema-3-el-modelo-muestra-o-tiempo-de-restablecimiento-anormal" aria-label="Permalink to &quot;Problema 3: El modelo muestra &quot;-&quot; o tiempo de restablecimiento anormal&quot;">​</a></h3><p><strong>Posibles causas</strong>:</p><ul><li>El campo resetTime devuelto por la API está ausente o tiene formato anormal</li><li>El modelo aún no tiene información de cuota</li></ul><p><strong>Solución</strong>:</p><ul><li>Esto es normal, mystatus mostrará &quot;-&quot; para indicar que los datos no están disponibles</li><li>Si todos los modelos muestran &quot;-&quot;, verifica la conexión de red o el estado de la API de Google Cloud</li></ul><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>Google Cloud Antigravity soporta 4 modelos: G3 Pro, G3 Image, G3 Flash, Claude</li><li>Cada modelo tiene una cuota independiente y tiempo de restablecimiento</li><li>Soporta gestión de múltiples cuentas, cada cuenta se muestra por separado</li><li>Se muestra advertencia cuando la tasa de uso supera el 80%</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../../advanced/google-setup/">Configuración avanzada de Google Cloud: múltiples cuentas y gestión de modelos</a></strong>。</p><p>Aprenderás:</p><ul><li>Cómo agregar y gestionar múltiples cuentas de Google Cloud</li><li>Comprender la relación de mapeo de los 4 modelos</li><li>Diferencias entre projectId y managedProjectId</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta de archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Configuración de modelos</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>Lógica de consulta de cuentas</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Refresco de token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>Extracción de cuota</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>Formato de salida</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>Definición de tipo</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>：API de consulta de cuota de Google Cloud</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>：API de refresco de token OAuth</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>：User-Agent de solicitudes API</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>queryGoogleUsage()</code>：Consulta la cuota de todas las cuentas de Antigravity</li><li><code>fetchAccountQuota()</code>：Consulta la cuota de una sola cuenta</li><li><code>extractModelQuotas()</code>：Extrae la cuota de los 4 modelos desde la respuesta de la API</li><li><code>formatAccountQuota()</code>：Formatea la visualización de la cuota de una sola cuenta</li></ul><p><strong>Reglas de mapeo de modelos</strong>:</p><ul><li>G3 Pro soporta <code>gemini-3-pro-high</code> y <code>gemini-3-pro-low</code>, usa la key principal con prioridad</li><li>Claude soporta <code>claude-opus-4-5-thinking</code> y <code>claude-opus-4-5</code>, usa la key principal con prioridad</li><li>G3 Image y G3 Flash solo tienen una key</li></ul></details>`,69)])])}const g=a(l,[["render",n]]);export{m as __pageData,g as default};
